def setup_logging(app):
    """Configure comprehensive logging for the Flask application."""

    log_dir = os.environ.get('LOG_DIR', 'logs')
    os.makedirs(log_dir, exist_ok=True)

    # Root logger
    root_logger = logging.getLogger()
    root_logger.setLevel(logging.DEBUG)

    # --- Console Handler ---
    console_handler = logging.StreamHandler()
    console_handler.setLevel(logging.INFO)
    console_formatter = JSONLikeFormatter()
    console_handler.setFormatter(console_formatter)

    # --- File Handler: All requests ---
    request_handler = logging.handlers.RotatingFileHandler(
        os.path.join(log_dir, 'requests.log'),
        maxBytes=10 * 1024 * 1024,  # 10MB
        backupCount=10
    )
    request_handler.setLevel(logging.DEBUG)
    request_handler.setFormatter(JSONLikeFormatter())

    # --- File Handler: Errors only ---
    error_handler = logging.handlers.RotatingFileHandler(
        os.path.join(log_dir, 'errors.log'),
        maxBytes=10 * 1024 * 1024,
        backupCount=10
    )
    error_handler.setLevel(logging.ERROR)
    error_handler.setFormatter(JSONLikeFormatter())

    # --- File Handler: Security/Auth events ---
    security_handler = logging.handlers.RotatingFileHandler(
        os.path.join(log_dir, 'security.log'),
        maxBytes=10 * 1024 * 1024,
        backupCount=10
    )
    security_handler.setLevel(logging.INFO)
    security_handler.setFormatter(JSONLikeFormatter())

    # App logger
    app_logger = logging.getLogger('app')
    app_logger.setLevel(logging.DEBUG)
    app_logger.addHandler(console_handler)
    app_logger.addHandler(request_handler)
    app_logger.addHandler(error_handler)

    # Security logger
    security_logger = logging.getLogger('security')
    security_logger.setLevel(logging.INFO)
    security_logger.addHandler(security_handler)
    security_logger.addHandler(console_handler)

    # Set restrictive permissions on log files
    for log_file in ['requests.log', 'errors.log', 'security.log']:
        filepath = os.path.join(log_dir, log_file)
        if os.path.exists(filepath):
            os.chmod(filepath, 0o640)

    return app_logger, security_logger


